-- =============================================================================
-- ARUNA AI — SUPABASE DATABASE SCHEMA WITH RLS POLICIES
-- =============================================================================
-- Generated by analyzing the full frontend codebase.
-- All tables use UUID primary keys, Row Level Security (RLS) is enabled on every
-- table, and policies follow the principle of least-privilege.
-- Run this file in the Supabase SQL editor (or via supabase db push).
-- =============================================================================


-- ---------------------------------------------------------------------------
-- EXTENSIONS
-- ---------------------------------------------------------------------------
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";
CREATE EXTENSION IF NOT EXISTS "pgcrypto";


-- ===========================================================================
-- 1. PROFILES
--    One row per auth.users entry. Extended user data lives here.
-- ===========================================================================
CREATE TABLE public.profiles (
  id             UUID PRIMARY KEY REFERENCES auth.users(id) ON DELETE CASCADE,
  full_name      TEXT NOT NULL DEFAULT '',
  email          TEXT NOT NULL,
  avatar_url     TEXT,
  -- Memory preferences (from SettingsPage)
  personal_space_memory   BOOLEAN NOT NULL DEFAULT TRUE,
  professional_space_memory BOOLEAN NOT NULL DEFAULT TRUE,
  created_at     TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at     TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

ALTER TABLE public.profiles ENABLE ROW LEVEL SECURITY;

-- Users can read and update only their own profile
CREATE POLICY "profiles_select_own" ON public.profiles
  FOR SELECT USING (auth.uid() = id);

CREATE POLICY "profiles_update_own" ON public.profiles
  FOR UPDATE USING (auth.uid() = id) WITH CHECK (auth.uid() = id);

-- Supabase trigger: auto-create a profile row on signup
CREATE OR REPLACE FUNCTION public.handle_new_user()
RETURNS TRIGGER LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
BEGIN
  INSERT INTO public.profiles (id, email, full_name)
  VALUES (
    NEW.id,
    NEW.email,
    COALESCE(NEW.raw_user_meta_data->>'full_name', '')
  );
  RETURN NEW;
END;
$$;

CREATE TRIGGER on_auth_user_created
  AFTER INSERT ON auth.users
  FOR EACH ROW EXECUTE PROCEDURE public.handle_new_user();

-- Auto-update updated_at
CREATE OR REPLACE FUNCTION public.set_updated_at()
RETURNS TRIGGER LANGUAGE plpgsql AS $$
BEGIN
  NEW.updated_at = NOW();
  RETURN NEW;
END;
$$;

CREATE TRIGGER profiles_updated_at
  BEFORE UPDATE ON public.profiles
  FOR EACH ROW EXECUTE PROCEDURE public.set_updated_at();


-- ===========================================================================
-- 2. WORKSPACES
--    Personal, Professional, or Shared workspaces.
-- ===========================================================================
CREATE TYPE public.workspace_type AS ENUM ('Personal', 'Professional', 'Shared');

CREATE TABLE public.workspaces (
  id           UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  owner_id     UUID NOT NULL REFERENCES public.profiles(id) ON DELETE CASCADE,
  name         TEXT NOT NULL,
  description  TEXT NOT NULL DEFAULT '',
  emoji        TEXT NOT NULL DEFAULT '🗂️',
  type         public.workspace_type NOT NULL DEFAULT 'Personal',
  is_pinned    BOOLEAN NOT NULL DEFAULT FALSE,
  -- Aggregate counters (updated by triggers / functions)
  chat_count   INT NOT NULL DEFAULT 0,
  file_count   INT NOT NULL DEFAULT 0,
  output_count INT NOT NULL DEFAULT 0,
  last_active_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  created_at   TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at   TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

ALTER TABLE public.workspaces ENABLE ROW LEVEL SECURITY;
CREATE TRIGGER workspaces_updated_at BEFORE UPDATE ON public.workspaces
  FOR EACH ROW EXECUTE PROCEDURE public.set_updated_at();


-- ===========================================================================
-- 3. WORKSPACE MEMBERS
--    Many-to-many: users ↔ workspaces.
--    Must be created BEFORE is_workspace_member() function below.
-- ===========================================================================
CREATE TYPE public.workspace_role AS ENUM ('owner', 'editor', 'viewer');

CREATE TABLE public.workspace_members (
  id           UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  workspace_id UUID NOT NULL REFERENCES public.workspaces(id) ON DELETE CASCADE,
  user_id      UUID NOT NULL REFERENCES public.profiles(id) ON DELETE CASCADE,
  role         public.workspace_role NOT NULL DEFAULT 'editor',
  joined_at    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  UNIQUE (workspace_id, user_id)
);

ALTER TABLE public.workspace_members ENABLE ROW LEVEL SECURITY;


-- ---------------------------------------------------------------------------
-- Helper: is the current user a member of (or owner of) a workspace?
-- Defined AFTER workspace_members table so the relation exists.
-- ---------------------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.is_workspace_member(workspace_id UUID)
RETURNS BOOLEAN LANGUAGE sql STABLE SECURITY DEFINER AS $$
  SELECT EXISTS (
    SELECT 1 FROM public.workspace_members
    WHERE workspace_id = $1 AND user_id = auth.uid()
  ) OR EXISTS (
    SELECT 1 FROM public.workspaces
    WHERE id = $1 AND owner_id = auth.uid()
  );
$$;


-- RLS policies for workspaces (now safe — helper function exists)
CREATE POLICY "workspaces_select" ON public.workspaces
  FOR SELECT USING (public.is_workspace_member(id));

CREATE POLICY "workspaces_insert_owner" ON public.workspaces
  FOR INSERT WITH CHECK (owner_id = auth.uid());

CREATE POLICY "workspaces_update_owner" ON public.workspaces
  FOR UPDATE USING (owner_id = auth.uid()) WITH CHECK (owner_id = auth.uid());

CREATE POLICY "workspaces_delete_owner" ON public.workspaces
  FOR DELETE USING (owner_id = auth.uid());


-- RLS policies for workspace_members (now safe — helper function exists)
-- Members can see other members of workspaces they belong to
CREATE POLICY "workspace_members_select" ON public.workspace_members
  FOR SELECT USING (public.is_workspace_member(workspace_id));

-- Only workspace owners can add/remove members
CREATE POLICY "workspace_members_insert_owner" ON public.workspace_members
  FOR INSERT WITH CHECK (
    EXISTS (
      SELECT 1 FROM public.workspaces
      WHERE id = workspace_id AND owner_id = auth.uid()
    )
  );

CREATE POLICY "workspace_members_delete_owner" ON public.workspace_members
  FOR DELETE USING (
    EXISTS (
      SELECT 1 FROM public.workspaces
      WHERE id = workspace_id AND owner_id = auth.uid()
    )
  );


-- ===========================================================================
-- 4. CHAT SESSIONS
-- ===========================================================================
CREATE TYPE public.chat_mode AS ENUM ('personal', 'professional', 'general');

CREATE TABLE public.chat_sessions (
  id           UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  user_id      UUID NOT NULL REFERENCES public.profiles(id) ON DELETE CASCADE,
  workspace_id UUID REFERENCES public.workspaces(id) ON DELETE SET NULL,
  title        TEXT NOT NULL DEFAULT 'New Chat',
  mode         public.chat_mode NOT NULL DEFAULT 'general',
  is_starred   BOOLEAN NOT NULL DEFAULT FALSE,
  is_archived  BOOLEAN NOT NULL DEFAULT FALSE,
  created_at   TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at   TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

ALTER TABLE public.chat_sessions ENABLE ROW LEVEL SECURITY;
CREATE TRIGGER chat_sessions_updated_at BEFORE UPDATE ON public.chat_sessions
  FOR EACH ROW EXECUTE PROCEDURE public.set_updated_at();

CREATE POLICY "chat_sessions_select" ON public.chat_sessions
  FOR SELECT USING (
    user_id = auth.uid()
    OR (workspace_id IS NOT NULL AND public.is_workspace_member(workspace_id))
  );

CREATE POLICY "chat_sessions_insert" ON public.chat_sessions
  FOR INSERT WITH CHECK (user_id = auth.uid());

CREATE POLICY "chat_sessions_update" ON public.chat_sessions
  FOR UPDATE USING (user_id = auth.uid()) WITH CHECK (user_id = auth.uid());

CREATE POLICY "chat_sessions_delete" ON public.chat_sessions
  FOR DELETE USING (user_id = auth.uid());


-- ===========================================================================
-- 5. MESSAGES
--    Individual messages within a chat session.
-- ===========================================================================
CREATE TYPE public.message_role AS ENUM ('user', 'assistant', 'system');

CREATE TABLE public.messages (
  id             UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  session_id     UUID NOT NULL REFERENCES public.chat_sessions(id) ON DELETE CASCADE,
  user_id        UUID REFERENCES public.profiles(id) ON DELETE SET NULL,
  role           public.message_role NOT NULL,
  content        TEXT NOT NULL,
  -- AI model used for assistant messages
  model          TEXT,
  -- Cost in smallest currency unit (paise)
  cost_paise     INT NOT NULL DEFAULT 0,
  -- Optional: attached file references (vault file IDs)
  attached_file_ids UUID[] DEFAULT '{}',
  created_at     TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

ALTER TABLE public.messages ENABLE ROW LEVEL SECURITY;

-- Can read messages if you can read the session
CREATE POLICY "messages_select" ON public.messages
  FOR SELECT USING (
    EXISTS (
      SELECT 1 FROM public.chat_sessions cs
      WHERE cs.id = session_id
        AND (cs.user_id = auth.uid()
             OR (cs.workspace_id IS NOT NULL
                 AND public.is_workspace_member(cs.workspace_id)))
    )
  );

CREATE POLICY "messages_insert" ON public.messages
  FOR INSERT WITH CHECK (
    EXISTS (
      SELECT 1 FROM public.chat_sessions cs
      WHERE cs.id = session_id AND cs.user_id = auth.uid()
    )
  );

-- Messages are immutable after creation — no UPDATE or DELETE policies.


-- ===========================================================================
-- 6. TASKS  (Agent Execution Records)
-- ===========================================================================
CREATE TYPE public.task_status AS ENUM ('Running', 'Queued', 'Completed', 'Failed', 'Cancelled');

CREATE TABLE public.tasks (
  id             UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  user_id        UUID NOT NULL REFERENCES public.profiles(id) ON DELETE CASCADE,
  workspace_id   UUID REFERENCES public.workspaces(id) ON DELETE SET NULL,
  session_id     UUID REFERENCES public.chat_sessions(id) ON DELETE SET NULL,
  title          TEXT NOT NULL,
  status         public.task_status NOT NULL DEFAULT 'Queued',
  model          TEXT NOT NULL DEFAULT 'gpt-4o',
  -- Cost in paise
  cost_paise     INT NOT NULL DEFAULT 0,
  -- Duration in seconds
  duration_secs  INT,
  progress       SMALLINT NOT NULL DEFAULT 0 CHECK (progress BETWEEN 0 AND 100),
  started_at     TIMESTAMPTZ,
  completed_at   TIMESTAMPTZ,
  created_at     TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at     TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

ALTER TABLE public.tasks ENABLE ROW LEVEL SECURITY;
CREATE TRIGGER tasks_updated_at BEFORE UPDATE ON public.tasks
  FOR EACH ROW EXECUTE PROCEDURE public.set_updated_at();

CREATE POLICY "tasks_select" ON public.tasks
  FOR SELECT USING (
    user_id = auth.uid()
    OR (workspace_id IS NOT NULL AND public.is_workspace_member(workspace_id))
  );

CREATE POLICY "tasks_insert" ON public.tasks
  FOR INSERT WITH CHECK (user_id = auth.uid());

-- Only the task owner or a service role can update tasks
CREATE POLICY "tasks_update" ON public.tasks
  FOR UPDATE USING (user_id = auth.uid()) WITH CHECK (user_id = auth.uid());

CREATE POLICY "tasks_delete" ON public.tasks
  FOR DELETE USING (user_id = auth.uid());


-- ===========================================================================
-- 7. TASK LOGS  (Step-by-step agent execution logs)
-- ===========================================================================
CREATE TYPE public.log_type AS ENUM ('planning', 'executing', 'reasoning', 'complete', 'error');

CREATE TABLE public.task_logs (
  id          UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  task_id     UUID NOT NULL REFERENCES public.tasks(id) ON DELETE CASCADE,
  type        public.log_type NOT NULL,
  description TEXT NOT NULL,
  -- Elapsed seconds since task start
  elapsed_secs INT NOT NULL DEFAULT 0,
  created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

ALTER TABLE public.task_logs ENABLE ROW LEVEL SECURITY;

CREATE POLICY "task_logs_select" ON public.task_logs
  FOR SELECT USING (
    EXISTS (
      SELECT 1 FROM public.tasks t
      WHERE t.id = task_id AND t.user_id = auth.uid()
    )
  );

CREATE POLICY "task_logs_insert" ON public.task_logs
  FOR INSERT WITH CHECK (
    EXISTS (
      SELECT 1 FROM public.tasks t
      WHERE t.id = task_id AND t.user_id = auth.uid()
    )
  );


-- ===========================================================================
-- 8. NOTIFICATIONS
-- ===========================================================================
CREATE TYPE public.notification_type AS ENUM ('task', 'approval', 'mention', 'system');

CREATE TABLE public.notifications (
  id            UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  user_id       UUID NOT NULL REFERENCES public.profiles(id) ON DELETE CASCADE,
  type          public.notification_type NOT NULL,
  title         TEXT NOT NULL,
  description   TEXT NOT NULL DEFAULT '',
  action_label  TEXT,
  action_url    TEXT,
  is_read       BOOLEAN NOT NULL DEFAULT FALSE,
  created_at    TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

ALTER TABLE public.notifications ENABLE ROW LEVEL SECURITY;

CREATE POLICY "notifications_select_own" ON public.notifications
  FOR SELECT USING (user_id = auth.uid());

CREATE POLICY "notifications_update_own" ON public.notifications
  FOR UPDATE USING (user_id = auth.uid()) WITH CHECK (user_id = auth.uid());

CREATE POLICY "notifications_delete_own" ON public.notifications
  FOR DELETE USING (user_id = auth.uid());

-- Service role (edge functions) can insert notifications for any user
-- No INSERT policy for authenticated role — use service role key from functions.


-- ===========================================================================
-- 9. APPROVALS  (Human-in-the-Loop)
-- ===========================================================================
CREATE TYPE public.approval_status AS ENUM ('Pending', 'Approved', 'Rejected', 'Modified');
CREATE TYPE public.risk_level     AS ENUM ('Low', 'Medium', 'High');

CREATE TABLE public.approvals (
  id                UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  user_id           UUID NOT NULL REFERENCES public.profiles(id) ON DELETE CASCADE,
  workspace_id      UUID REFERENCES public.workspaces(id) ON DELETE SET NULL,
  task_id           UUID REFERENCES public.tasks(id) ON DELETE SET NULL,
  title             TEXT NOT NULL,
  description       TEXT NOT NULL DEFAULT '',
  status            public.approval_status NOT NULL DEFAULT 'Pending',
  risk              public.risk_level NOT NULL DEFAULT 'Low',
  goal              TEXT,
  risk_explanation  TEXT,
  -- JSONB payload with action-specific details (recipients, integration, etc.)
  details           JSONB NOT NULL DEFAULT '{}',
  requester         TEXT NOT NULL DEFAULT 'Automated Workflow',
  reviewed_at       TIMESTAMPTZ,
  created_at        TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at        TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

ALTER TABLE public.approvals ENABLE ROW LEVEL SECURITY;
CREATE TRIGGER approvals_updated_at BEFORE UPDATE ON public.approvals
  FOR EACH ROW EXECUTE PROCEDURE public.set_updated_at();

CREATE POLICY "approvals_select" ON public.approvals
  FOR SELECT USING (
    user_id = auth.uid()
    OR (workspace_id IS NOT NULL AND public.is_workspace_member(workspace_id))
  );

CREATE POLICY "approvals_insert" ON public.approvals
  FOR INSERT WITH CHECK (user_id = auth.uid());

-- Only the owner can approve/reject (update status)
CREATE POLICY "approvals_update" ON public.approvals
  FOR UPDATE USING (user_id = auth.uid()) WITH CHECK (user_id = auth.uid());


-- ===========================================================================
-- 10. VAULT FILES
-- ===========================================================================
CREATE TABLE public.vault_files (
  id             UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  workspace_id   UUID REFERENCES public.workspaces(id) ON DELETE SET NULL,
