  -- Storage path inside Supabase Storage bucket "vault"
  storage_path   TEXT NOT NULL UNIQUE,
  mime_type      TEXT NOT NULL DEFAULT 'application/octet-stream',
  size_bytes     BIGINT NOT NULL DEFAULT 0,
  -- Human-friendly type label: pdf, doc, sheet, slide, image, other
  file_type      TEXT NOT NULL DEFAULT 'other',
  is_agent_generated BOOLEAN NOT NULL DEFAULT FALSE,
  created_at     TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at     TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

ALTER TABLE public.vault_files ENABLE ROW LEVEL SECURITY;
CREATE TRIGGER vault_files_updated_at BEFORE UPDATE ON public.vault_files
  FOR EACH ROW EXECUTE PROCEDURE public.set_updated_at();

CREATE POLICY "vault_files_select" ON public.vault_files
  FOR SELECT USING (
    uploader_id = auth.uid()
    OR (workspace_id IS NOT NULL AND public.is_workspace_member(workspace_id))
  );

CREATE POLICY "vault_files_insert" ON public.vault_files
  FOR INSERT WITH CHECK (uploader_id = auth.uid());

CREATE POLICY "vault_files_update" ON public.vault_files
  FOR UPDATE USING (uploader_id = auth.uid()) WITH CHECK (uploader_id = auth.uid());

CREATE POLICY "vault_files_delete" ON public.vault_files
  FOR DELETE USING (uploader_id = auth.uid());


-- ===========================================================================
-- 11. INTEGRATIONS
--    Tracks which third-party tools each user has connected.
-- ===========================================================================
CREATE TYPE public.integration_status AS ENUM ('connected', 'disconnected', 'error');

CREATE TABLE public.integrations (
  id             UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  user_id        UUID NOT NULL REFERENCES public.profiles(id) ON DELETE CASCADE,
  -- Canonical integration identifier: "slack", "google_drive", "gmail", etc.
  provider       TEXT NOT NULL,
  display_name   TEXT NOT NULL,
  status         public.integration_status NOT NULL DEFAULT 'disconnected',
  -- Whether the agent can act on this integration without human approval
  autonomous     BOOLEAN NOT NULL DEFAULT FALSE,
  -- OAuth tokens stored encrypted (use Supabase Vault / pgcrypto in prod)
  access_token   TEXT,
  refresh_token  TEXT,
  token_expires_at TIMESTAMPTZ,
  -- Extra provider-specific config
  metadata       JSONB NOT NULL DEFAULT '{}',
  created_at     TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at     TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  UNIQUE (user_id, provider)
);

ALTER TABLE public.integrations ENABLE ROW LEVEL SECURITY;
CREATE TRIGGER integrations_updated_at BEFORE UPDATE ON public.integrations
  FOR EACH ROW EXECUTE PROCEDURE public.set_updated_at();

CREATE POLICY "integrations_select_own" ON public.integrations
  FOR SELECT USING (user_id = auth.uid());

CREATE POLICY "integrations_insert_own" ON public.integrations
  FOR INSERT WITH CHECK (user_id = auth.uid());

CREATE POLICY "integrations_update_own" ON public.integrations
  FOR UPDATE USING (user_id = auth.uid()) WITH CHECK (user_id = auth.uid());

CREATE POLICY "integrations_delete_own" ON public.integrations
  FOR DELETE USING (user_id = auth.uid());


-- ===========================================================================
-- 12. WORKSPACE MEMORY
--    Key facts the AI remembers about a workspace.
-- ===========================================================================
CREATE TABLE public.workspace_memory (
  id           UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  workspace_id UUID NOT NULL REFERENCES public.workspaces(id) ON DELETE CASCADE,
  -- The user or agent that added this fact
  added_by     UUID REFERENCES public.profiles(id) ON DELETE SET NULL,
  fact         TEXT NOT NULL,
  -- Embedding vector for semantic search (requires pgvector extension)
  -- embedding   VECTOR(1536),
  created_at   TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at   TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

ALTER TABLE public.workspace_memory ENABLE ROW LEVEL SECURITY;
CREATE TRIGGER workspace_memory_updated_at BEFORE UPDATE ON public.workspace_memory
  FOR EACH ROW EXECUTE PROCEDURE public.set_updated_at();

CREATE POLICY "workspace_memory_select" ON public.workspace_memory
  FOR SELECT USING (public.is_workspace_member(workspace_id));

CREATE POLICY "workspace_memory_insert" ON public.workspace_memory
  FOR INSERT WITH CHECK (public.is_workspace_member(workspace_id));

CREATE POLICY "workspace_memory_update" ON public.workspace_memory
  FOR UPDATE USING (public.is_workspace_member(workspace_id))
  WITH CHECK (public.is_workspace_member(workspace_id));

CREATE POLICY "workspace_memory_delete" ON public.workspace_memory
  FOR DELETE USING (
    EXISTS (
      SELECT 1 FROM public.workspaces w
      WHERE w.id = workspace_id AND w.owner_id = auth.uid()
    )
    OR added_by = auth.uid()
  );


-- ===========================================================================
-- 13. ACTIVITY LOGS
--    Append-only audit trail for workspace events.
-- ===========================================================================
CREATE TABLE public.activity_logs (
  id           UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  workspace_id UUID REFERENCES public.workspaces(id) ON DELETE CASCADE,
  user_id      UUID REFERENCES public.profiles(id) ON DELETE SET NULL,
  action       TEXT NOT NULL,          -- e.g. "uploaded", "shared", "approved"
  target       TEXT NOT NULL,          -- e.g. "Q3 Report.pdf"
  target_id    UUID,                   -- optional FK to affected row
  target_type  TEXT,                   -- e.g. "vault_file", "approval", "task"
  metadata     JSONB NOT NULL DEFAULT '{}',
  created_at   TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

ALTER TABLE public.activity_logs ENABLE ROW LEVEL SECURITY;

CREATE POLICY "activity_logs_select" ON public.activity_logs
  FOR SELECT USING (
    user_id = auth.uid()
    OR (workspace_id IS NOT NULL AND public.is_workspace_member(workspace_id))
  );

-- Inserts happen via service-role edge functions only — no user INSERT policy.


-- ===========================================================================
-- 14. BILLING / USAGE RECORDS
