-- ===========================================================================
-- 16. WORKFLOWS
-- ===========================================================================
CREATE TYPE public.workflow_status AS ENUM ('active', 'paused', 'draft', 'archived');

CREATE TABLE public.workflows (
  id             UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  workspace_id   UUID NOT NULL REFERENCES public.workspaces(id) ON DELETE CASCADE,
  created_by     UUID NOT NULL REFERENCES public.profiles(id) ON DELETE CASCADE,
  name           TEXT NOT NULL,
  description    TEXT NOT NULL DEFAULT '',
  status         public.workflow_status NOT NULL DEFAULT 'draft',
  -- Workflow definition (DAG of steps) stored as JSONB
  definition     JSONB NOT NULL DEFAULT '{}',
  -- Cron schedule (nullable = manual trigger only)
  schedule       TEXT,
  last_run_at    TIMESTAMPTZ,
  created_at     TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at     TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

ALTER TABLE public.workflows ENABLE ROW LEVEL SECURITY;
CREATE TRIGGER workflows_updated_at BEFORE UPDATE ON public.workflows
  FOR EACH ROW EXECUTE PROCEDURE public.set_updated_at();

CREATE POLICY "workflows_select" ON public.workflows
  FOR SELECT USING (public.is_workspace_member(workspace_id));

CREATE POLICY "workflows_insert" ON public.workflows
  FOR INSERT WITH CHECK (
    created_by = auth.uid()
    AND public.is_workspace_member(workspace_id)
  );

CREATE POLICY "workflows_update" ON public.workflows
  FOR UPDATE USING (
    created_by = auth.uid()
    OR EXISTS (
      SELECT 1 FROM public.workspace_members wm
      WHERE wm.workspace_id = workflows.workspace_id
        AND wm.user_id = auth.uid()
        AND wm.role IN ('owner', 'editor')
    )
  );

CREATE POLICY "workflows_delete" ON public.workflows
  FOR DELETE USING (
    created_by = auth.uid()
    OR EXISTS (
      SELECT 1 FROM public.workspaces w
      WHERE w.id = workspace_id AND w.owner_id = auth.uid()
    )
  );


-- ===========================================================================
-- 17. CONTACT INQUIRIES  (from the public /contact page)
-- ===========================================================================
CREATE TYPE public.inquiry_type AS ENUM ('general', 'enterprise', 'partnership', 'support');

CREATE TABLE public.contact_inquiries (
  id           UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  first_name   TEXT NOT NULL,
  last_name    TEXT NOT NULL,
  work_email   TEXT NOT NULL,
  inquiry      public.inquiry_type NOT NULL DEFAULT 'general',
  message      TEXT NOT NULL,
  -- Optional: link to registered user if they were logged in
  user_id      UUID REFERENCES public.profiles(id) ON DELETE SET NULL,
  is_resolved  BOOLEAN NOT NULL DEFAULT FALSE,
  created_at   TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

ALTER TABLE public.contact_inquiries ENABLE ROW LEVEL SECURITY;

-- Public users (anon role) can insert; only service role can read all rows.
CREATE POLICY "contact_inquiries_insert_anon" ON public.contact_inquiries
  FOR INSERT WITH CHECK (TRUE);

-- Logged-in users can see their own submissions
CREATE POLICY "contact_inquiries_select_own" ON public.contact_inquiries
  FOR SELECT USING (user_id = auth.uid());


-- ===========================================================================
-- 18. USER SETTINGS  (model preferences, UI preferences, etc.)
--    One row per user, defaults lazily inserted on first write.
-- ===========================================================================
CREATE TABLE public.user_settings (
  user_id          UUID PRIMARY KEY REFERENCES public.profiles(id) ON DELETE CASCADE,
  -- Preferred AI tier: 'faster' | 'balanced' | 'best'
  model_tier       TEXT NOT NULL DEFAULT 'balanced',
  -- Preferred default chat mode
  default_mode     public.chat_mode NOT NULL DEFAULT 'general',
  -- Monthly budget in paise
  monthly_budget_paise BIGINT NOT NULL DEFAULT 150000,
  -- Notification preferences (granular toggles as JSONB)
  notification_prefs JSONB NOT NULL DEFAULT '{"tasks":true,"approvals":true,"mentions":true,"system":true}',
  -- Theme: 'light' | 'dark' | 'system'
  theme            TEXT NOT NULL DEFAULT 'system',
  updated_at       TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

ALTER TABLE public.user_settings ENABLE ROW LEVEL SECURITY;
CREATE TRIGGER user_settings_updated_at BEFORE UPDATE ON public.user_settings
  FOR EACH ROW EXECUTE PROCEDURE public.set_updated_at();

CREATE POLICY "user_settings_select_own" ON public.user_settings
  FOR SELECT USING (user_id = auth.uid());

CREATE POLICY "user_settings_insert_own" ON public.user_settings
  FOR INSERT WITH CHECK (user_id = auth.uid());

CREATE POLICY "user_settings_update_own" ON public.user_settings
  FOR UPDATE USING (user_id = auth.uid()) WITH CHECK (user_id = auth.uid());


-- ===========================================================================
-- INDEXES  (performance on common query patterns)
-- ===========================================================================
-- Chat sessions
CREATE INDEX idx_chat_sessions_user       ON public.chat_sessions(user_id);
CREATE INDEX idx_chat_sessions_workspace  ON public.chat_sessions(workspace_id);
CREATE INDEX idx_chat_sessions_created    ON public.chat_sessions(created_at DESC);

-- Messages
CREATE INDEX idx_messages_session         ON public.messages(session_id);
CREATE INDEX idx_messages_created         ON public.messages(created_at);

-- Tasks
CREATE INDEX idx_tasks_user              ON public.tasks(user_id);
CREATE INDEX idx_tasks_workspace         ON public.tasks(workspace_id);
CREATE INDEX idx_tasks_status            ON public.tasks(status);
CREATE INDEX idx_tasks_created           ON public.tasks(created_at DESC);

-- Task logs
CREATE INDEX idx_task_logs_task          ON public.task_logs(task_id);

-- Notifications
CREATE INDEX idx_notifications_user      ON public.notifications(user_id);
CREATE INDEX idx_notifications_unread    ON public.notifications(user_id, is_read) WHERE is_read = FALSE;

-- Approvals
CREATE INDEX idx_approvals_user          ON public.approvals(user_id);
CREATE INDEX idx_approvals_workspace     ON public.approvals(workspace_id);
CREATE INDEX idx_approvals_status        ON public.approvals(status);

-- Vault files
CREATE INDEX idx_vault_files_workspace   ON public.vault_files(workspace_id);
CREATE INDEX idx_vault_files_uploader    ON public.vault_files(uploader_id);

-- Activity logs
CREATE INDEX idx_activity_workspace      ON public.activity_logs(workspace_id);
CREATE INDEX idx_activity_created        ON public.activity_logs(created_at DESC);

-- Billing
CREATE INDEX idx_billing_user            ON public.billing_records(user_id);
CREATE INDEX idx_billing_created         ON public.billing_records(created_at DESC);

-- Workspace memory
CREATE INDEX idx_workspace_memory_ws     ON public.workspace_memory(workspace_id);

-- Workflows
CREATE INDEX idx_workflows_workspace     ON public.workflows(workspace_id);


-- ===========================================================================
-- STORAGE BUCKETS (run via Supabase Dashboard or Management API)
-- ===========================================================================
-- bucket: "vault"         — user-uploaded files and agent outputs
--   public: false
--   allowed mime types: * (any)
--   max file size: 50MB
--
-- bucket: "avatars"       — user profile pictures
--   public: true
--   allowed mime types: image/*
--   max file size: 2MB
--
-- Storage RLS for "vault" bucket:
--   SELECT: auth.uid() IS NOT NULL  (authenticated reads only; files checked via vault_files table)
--   INSERT: auth.uid() IS NOT NULL
--   DELETE: owner only (checked via service function)


-- ===========================================================================
-- REALTIME SUBSCRIPTIONS (enable in Supabase Dashboard)
-- ===========================================================================
-- Enable realtime on:
--   • messages           — live chat streaming
--   • tasks              — live task status updates
--   • task_logs          — live agent log streaming
--   • notifications      — push notifications to user
--   • approvals          — live approval queue

ALTER PUBLICATION supabase_realtime ADD TABLE public.messages;
ALTER PUBLICATION supabase_realtime ADD TABLE public.tasks;
ALTER PUBLICATION supabase_realtime ADD TABLE public.task_logs;
ALTER PUBLICATION supabase_realtime ADD TABLE public.notifications;
ALTER PUBLICATION supabase_realtime ADD TABLE public.approvals;


-- ===========================================================================
-- HELPER VIEWS
-- ===========================================================================

-- Current user's unread notification count
CREATE OR REPLACE VIEW public.unread_notification_count AS
  SELECT COUNT(*) AS count
  FROM public.notifications
  WHERE user_id = auth.uid() AND is_read = FALSE;

-- This month's billing summary for the current user
CREATE OR REPLACE VIEW public.current_month_usage AS
  SELECT
    SUM(cost_paise)                        AS total_paise,
    SUM(input_tokens + output_tokens)      AS total_tokens,
    COUNT(*)                               AS total_calls,
    model
  FROM public.billing_records
  WHERE user_id = auth.uid()
    AND date_trunc('month', created_at) = date_trunc('month', NOW())
  GROUP BY model;


